function solve(m: number, n: number, waitCost: number[][]): number {
    // Directions: right and down
    const directions = [[0, 1], [1, 0]];

    // Priority queue for Dijkstra's algorithm
    const pq = new PriorityQueue<{ row: number, col: number, time: number, cost: number }>((a, b) => a.cost - b.cost);
    pq.enqueue({ row: 0, col: 0, time: 1, cost: (0 + 1) * (0 + 1) });

    // Visited matrix to track the minimum cost to reach each cell at each time
    const visited = Array(m).fill(null).map(() => Array(n).fill(null).map(() => Array(2).fill(Infinity)));

    // Start at (0, 0) with time 1 and cost (0+1)*(0+1) = 1
    visited[0][0][1 % 2] = (0 + 1) * (0 + 1);

    while (!pq.isEmpty()) {
        const { row, col, time, cost } = pq.dequeue()!;

        // If we reached the destination
        if (row === m - 1 && col === n - 1) {
            return cost;
        }

        // Check if we have already found a better path to this cell at this time
        if (visited[row][col][time % 2] < cost) {
            continue;
        }

        // Move right or down
        for (const [dr, dc] of directions) {
            const newRow = row + dr;
            const newCol = col + dc;

            // Check if the new cell is within bounds
            if (newRow >= 0 && newRow < m && newCol >= 0 && newCol < n) {
                const newTime = time + 1;
                const newCost = cost + (newRow + 1) * (newCol + 1);

                // If this is a better path, update and enqueue
                if (visited[newRow][newCol][newTime % 2] > newCost) {
                    visited[newRow][newCol][newTime % 2] = newCost;
                    pq.enqueue({ row: newRow, col: newCol, time: newTime, cost: newCost });
                }
            }
        }

        // If time is even, we need to wait
        if (time % 2 === 0) {
            const newTime = time + 1;
            const newCost = cost + waitCost[row][col];

            // If this is a better path, update and enqueue
            if (visited[row][col][newTime % 2] > newCost) {
                visited[row][col][newTime % 2] = newCost;
                pq.enqueue({ row, col, time: newTime, cost: newCost });
            }
        }
    }

    // If we couldn't reach the destination
    return -1;
}

// Priority queue implementation
class PriorityQueue<T> {
    private heap: T[];
    private comparator: (a: T, b: T) => number;

    constructor(comparator: (a: T, b: T) => number) {
        this.heap = [];
        this.comparator = comparator;
    }

    enqueue(item: T): void {
        this.heap.push(item);
        this.heapifyUp(this.heap.length - 1);
    }

    dequeue(): T | undefined {
        if (this.heap.length === 0) return undefined;

        const item = this.heap[0];
        this.heap[0] = this.heap.pop()!;
        this.heapifyDown(0);

        return item;
    }

    isEmpty(): boolean {
        return this.heap.length === 0;
    }

    private heapifyUp(index: number): void {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);

            if (this.comparator(this.heap[index], this.heap[parentIndex]) >= 0) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    private heapifyDown(index: number): void {
        const leftChild = 2 * index + 1;
        const rightChild = 2 * index + 2;
        let smallest = index;

        if (leftChild < this.heap.length && this.comparator(this.heap[leftChild], this.heap[smallest]) < 0) {
            smallest = leftChild;
        }

        if (rightChild < this.heap.length && this.comparator(this.heap[rightChild], this.heap[smallest]) < 0) {
            smallest = rightChild;
        }

        if (smallest !== index) {
            [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
            this.heapifyDown(smallest);
        }
    }
}

