    const directions = [[0, 1], [1, 0]];

    // Priority queue for Dijkstra's algorithm
    const pq = new PriorityQueue<{ row: number, col: number, time: number, cost: number }>((a, b) => a.cost - b.cost);
    pq.enqueue({ row: 0, col: 0, time: 1, cost: (0 + 1) * (0 + 1) });

    // Visited matrix to track the minimum cost to reach each cell at each time
    const visited = Array(m).fill(null).map(() => Array(n).fill(null).map(() => Array(2).fill(Infinity)));

    // Start at (0, 0) with time 1 and cost (0+1)*(0+1) = 1
    visited[0][0][1 % 2] = (0 + 1) * (0 + 1);

    while (!pq.isEmpty()) {
        const { row, col, time, cost } = pq.dequeue()!;

        // If we reached the destination
        if (row === m - 1 && col === n - 1) {
            return cost;
        }

        // Check if we have already found a better path to this cell at this time
        if (visited[row][col][time % 2] < cost) {
            continue;
        }

