                    pq.enqueue({ row: newRow, col: newCol, time: newTime, cost: newCost });
                }
            }
        }

        // If time is even, we need to wait
        if (time % 2 === 0) {
            const newTime = time + 1;
            const newCost = cost + waitCost[row][col];

            // If this is a better path, update and enqueue
            if (visited[row][col][newTime % 2] > newCost) {
                visited[row][col][newTime % 2] = newCost;
                pq.enqueue({ row, col, time: newTime, cost: newCost });
            }
        }
    }

    // If we couldn't reach the destination
    return -1;
}

